const hairNetworks = {};

window.addEventListener("DOMContentLoaded", () => {
  console.info("시각화 라이브러리는 원본 HTML의 주요 버전을 유지했습니다: D3 7, D3-cloud 1, vis-network 9.1.9");
  renderBasicAnalysis();
  renderWordCloud();
  renderAllSemanticNetwork();
  renderHairBarCharts();
  renderHairSemanticNetworks();
  setupFadeIn();
});

window.addEventListener("resize", debounce(() => {
  d3.select("#word-cloud").selectAll("*").remove();
  renderWordCloudOnly();
  renderHairBarCharts(true);
  if (allNetwork) allNetwork.fit();
  Object.values(hairNetworks).forEach(network => network && network.fit());
}, 250));

function renderBasicAnalysis() {
  d3.select("#overall-cards").selectAll(".stat-card")
    .data(ARTICLE_DATA.overall)
    .join("div")
    .attr("class", "stat-card")
    .html(d => `<strong>${Number(d["비율(%)"]).toFixed(2)}%</strong><span>${d["위험도"]} · ${Number(d["건수"]).toLocaleString()}건</span>`);
  makeTable("#metric-table", ARTICLE_DATA.metrics, ["주제", "전체_건수", "평균_체크리스트_개수", "검토 우선_비율(%)", "검토 필요_비율(%)", "검토 낮음_비율(%)", "정상광고_비율(%)"]);
  makeTable("#risk-table", ARTICLE_DATA.categoryRisk, ["주제", "위험도", "건수", "비율(%)"]);
}

function makeTable(selector, rows, columns) {
  const root = d3.select(selector);
  root.selectAll("*").remove();
  const table = root.append("table");
  table.append("thead").append("tr").selectAll("th").data(columns).join("th").text(d => d);
  table.append("tbody").selectAll("tr").data(rows).join("tr")
    .selectAll("td")
    .data(row => columns.map(col => row[col]))
    .join("td")
    .text(d => typeof d === "number" ? d.toLocaleString() : d);
}

function renderWordCloud() {
  const summary = ARTICLE_DATA.summaryData;
  d3.select("#word-summary").selectAll(".mini-card")
    .data(summary.category_summary)
    .join("div")
    .attr("class", "mini-card")
    .html(d => `<strong>${d.category}</strong>전체 댓글 ${Number(d.total_comments).toLocaleString()}건<br>텍스트 댓글 ${Number(d.nonempty_comments).toLocaleString()}건`);
  d3.select("#word-top-table").selectAll("tr")
    .data(ARTICLE_DATA.wordData.slice(0, 20))
    .join("tr")
    .selectAll("td")
    .data((d, i) => [i + 1, d.text, d.count])
    .join("td")
    .text(d => typeof d === "number" ? d.toLocaleString() : d);
  renderWordCloudOnly();
}

function renderWordCloudOnly() {
  const container = document.getElementById("word-cloud");
  if (!container || !window.d3 || !d3.layout || !d3.layout.cloud) return;
  const words = ARTICLE_DATA.wordData;
  const width = container.clientWidth || 900;
  const height = Math.max(430, Math.min(620, Math.round(width * 0.6)));
  const svg = d3.select(container).append("svg").attr("viewBox", `0 0 ${width} ${height}`).attr("width", "100%").attr("height", height);
  d3.layout.cloud()
    .size([width, height])
    .words(words.map(d => ({ text: d.text, size: d.size, count: d.count })))
    .padding(4)
    .rotate(() => Math.random() > 0.82 ? 90 : 0)
    .font('Noto Sans KR, Malgun Gothic, sans-serif')
    .fontSize(d => d.size)
    .on("end", placed => {
      svg.append("g")
        .attr("transform", `translate(${width / 2},${height / 2})`)
        .selectAll("text")
        .data(placed)
        .join("text")
        .style("font-family", "Noto Sans KR, Malgun Gothic, sans-serif")
        .style("font-size", d => `${d.size}px`)
        .style("font-weight", d => d.count >= words[4]?.count ? 900 : 700)
        .style("fill", (d, i) => WORD_PALETTE[i % WORD_PALETTE.length])
        .attr("text-anchor", "middle")
        .attr("transform", d => `translate(${d.x},${d.y}) rotate(${d.rotate})`)
        .text(d => d.text)
        .append("title")
        .text(d => `${d.text}: ${Number(d.count).toLocaleString()}회`);
    })
    .start();
}

function renderAllSemanticNetwork() {
  const data = ARTICLE_DATA.networkData;
  d3.select("#network-summary").selectAll(".mini-card")
    .data(data.meta.category_summary)
    .join("div")
    .attr("class", "mini-card")
    .html(d => `<strong>${d.category}</strong>전체 댓글 ${Number(d.total_comments).toLocaleString()}건<br>텍스트 댓글 ${Number(d.nonempty_comments).toLocaleString()}건`);
  document.getElementById("all-node-count").addEventListener("input", renderAllNetworkOnly);
  document.getElementById("all-min-edge").addEventListener("input", renderAllNetworkOnly);
  renderAllNetworkOnly();
}

function renderAllNetworkOnly() {
  const data = ARTICLE_DATA.networkData;
  const limit = Number(document.getElementById("all-node-count").value);
  const minCount = Number(document.getElementById("all-min-edge").value);
  document.getElementById("all-node-count-out").textContent = limit;
  document.getElementById("all-min-edge-out").textContent = minCount;
  const allowed = new Set(data.nodes.filter(d => d.rank <= limit).map(d => d.id));
  const nodes = data.nodes.filter(d => allowed.has(d.id)).map(d => ({
    ...d,
    color: { background: WORD_PALETTE[d.rank % WORD_PALETTE.length], border: "#111111", highlight: { background: "#f6e27f", border: "#111111" } },
    font: { face: "Noto Sans KR, Malgun Gothic, sans-serif", size: 17, color: "#111111" },
    borderWidth: 1.4
  }));
  const edges = data.edges.filter(d => d.count >= minCount && allowed.has(d.from) && allowed.has(d.to)).map(d => ({
    ...d,
    width: Math.max(1, Math.log2(d.count + 1)),
    color: { color: "rgba(51, 51, 51, .36)", highlight: "#111111" },
    smooth: { type: "continuous" }
  }));
  if (allNetwork) allNetwork.destroy();
  allNetwork = new vis.Network(document.getElementById("all-network"), { nodes: new vis.DataSet(nodes), edges: new vis.DataSet(edges) }, networkOptions(155, -12000));
  allNetwork.once("stabilizationIterationsDone", () => { allNetwork.setOptions({ physics: false }); allNetwork.fit(); });
}

function renderHairBarCharts(redraw = false) {
  const container = d3.select("#hair-bar-grid");
  if (redraw) container.selectAll("*").remove();
  const data = ARTICLE_DATA.hairBarData;
  const tooltip = ensureTooltip();
  if (container.selectAll(".chart-card").empty()) {
    data.labels.forEach(label => {
      const s = data.summary[label] || {};
      container.append("section")
        .attr("class", "chart-card")
        .html(`<h4 style="color:${chartColor(label)}">${label}</h4><p class="meta">댓글 ${Number(s.comment_count || 0).toLocaleString()}개 · ‘탈모’ 제외 상위 10개 단어</p><div id="hair-bar-${cssId(label)}" class="bar-chart"></div>`);
    });
  }
  data.labels.forEach(label => {
    const selector = "#hair-bar-" + cssId(label);
    d3.select(selector).selectAll("*").remove();
    renderBarChart(selector, label, data.bar_data[label] || [], chartColor(label), tooltip);
  });
}

function renderBarChart(selector, label, rows, color, tooltip) {
  const container = document.querySelector(selector);
  const width = container.clientWidth || 500;
  const height = 340;
  const margin = { top: 16, right: 44, bottom: 30, left: 88 };
  const svg = d3.select(selector).append("svg").attr("viewBox", `0 0 ${width} ${height}`).attr("width", "100%").attr("height", height);
  const x = d3.scaleLinear().domain([0, d3.max(rows, d => d.count) || 1]).nice().range([margin.left, width - margin.right]);
  const y = d3.scaleBand().domain(rows.map(d => d.word)).range([margin.top, height - margin.bottom]).padding(0.22);
  svg.append("g").attr("class", "axis").attr("transform", `translate(0,${height - margin.bottom})`).call(d3.axisBottom(x).ticks(4).tickFormat(d3.format(",")));
  svg.append("g").attr("class", "axis").attr("transform", `translate(${margin.left},0)`).call(d3.axisLeft(y));
  svg.selectAll("rect.bar").data(rows).join("rect")
    .attr("class", "bar")
    .attr("x", margin.left)
    .attr("y", d => y(d.word))
    .attr("width", d => x(d.count) - margin.left)
    .attr("height", y.bandwidth())
    .attr("rx", 4)
    .attr("fill", color)
    .attr("opacity", .88)
    .on("mouseenter", (event, d) => {
      d3.select(event.currentTarget).attr("opacity", 1);
      tooltip.style.opacity = 1;
      tooltip.innerHTML = `<strong>${label} · ${d.word}</strong>등장 횟수: ${Number(d.count).toLocaleString()}회`;
    })
    .on("mousemove", event => { tooltip.style.left = event.clientX + "px"; tooltip.style.top = event.clientY + "px"; })
    .on("mouseleave", event => { d3.select(event.currentTarget).attr("opacity", .88); tooltip.style.opacity = 0; });
  svg.selectAll("text.bar-label").data(rows).join("text")
    .attr("class", "bar-label")
    .attr("x", d => x(d.count) + 7)
    .attr("y", d => y(d.word) + y.bandwidth() / 2 + 4)
    .text(d => Number(d.count).toLocaleString());
}

function renderHairSemanticNetworks() {
  const data = ARTICLE_DATA.hairNetworkData;
  const grid = document.getElementById("hair-network-grid");
  data.labels.forEach(label => {
    const s = data.summary[label] || {};
    const section = document.createElement("section");
    section.className = "chart-card";
    section.innerHTML = `<h4 style="color:${chartColor(label)}">${label}</h4><p class="meta">댓글 ${Number(s.comment_count || 0).toLocaleString()}개</p><div id="hair-network-${cssId(label)}" class="topic-network"></div>`;
    grid.appendChild(section);
  });
  document.getElementById("hair-node-count").addEventListener("input", renderHairNetworksOnly);
  document.getElementById("hair-edge-count").addEventListener("input", renderHairNetworksOnly);
  renderHairNetworksOnly();
}

function renderHairNetworksOnly() {
  const data = ARTICLE_DATA.hairNetworkData;
  const nodeLimit = Number(document.getElementById("hair-node-count").value);
  const minEdge = Number(document.getElementById("hair-edge-count").value);
  document.getElementById("hair-node-out").textContent = nodeLimit;
  document.getElementById("hair-edge-out").textContent = minEdge;
  data.labels.forEach(label => renderHairNetwork(label, nodeLimit, minEdge));
}

function renderHairNetwork(label, nodeLimit, minEdge) {
  const data = ARTICLE_DATA.hairNetworkData;
  const id = "hair-network-" + cssId(label);
  const raw = data.network_data[label] || { nodes: [], edges: [] };
  const allowed = new Set(raw.nodes.filter(d => d.rank <= nodeLimit).map(d => d.id));
  const color = chartColor(label);
  const edges = raw.edges.filter(d => d.count >= minEdge && allowed.has(d.from) && allowed.has(d.to)).map(d => ({
    ...d,
    width: Math.max(1, Math.log2(d.count + 1)),
    color: { color: "rgba(51,51,51,.42)", highlight: "#111111" }
  }));
  const connected = new Set();
  edges.forEach(e => { connected.add(e.from); connected.add(e.to); });
  const nodes = raw.nodes.filter(d => allowed.has(d.id) && connected.has(d.id)).map(d => ({
    ...d,
    color: { background: color, border: "#111111" },
    font: { face: "Noto Sans KR, Malgun Gothic, sans-serif", size: 15, color: "#111111" }
  }));
  const el = document.getElementById(id);
  if (hairNetworks[id]) hairNetworks[id].destroy();
  if (!nodes.length) {
    el.innerHTML = '<div class="empty-network">표시할 연결망 데이터가 없습니다</div>';
    return;
  }
  el.innerHTML = "";
  hairNetworks[id] = new vis.Network(el, { nodes: new vis.DataSet(nodes), edges: new vis.DataSet(edges) }, networkOptions(135, -8000));
  hairNetworks[id].once("stabilizationIterationsDone", () => { hairNetworks[id].setOptions({ physics: false }); hairNetworks[id].fit({ animation: { duration: 450, easingFunction: "easeInOutQuad" } }); });
}

function networkOptions(springLength, gravity) {
  return {
    autoResize: true,
    interaction: { hover: true, tooltipDelay: 120, navigationButtons: true, keyboard: false },
    nodes: { shape: "dot", scaling: { min: 14, max: 54 } },
    edges: { scaling: { min: 1, max: 10 } },
    physics: {
      stabilization: { iterations: 220 },
      barnesHut: { gravitationalConstant: gravity, centralGravity: 0.22, springLength, springConstant: 0.04, damping: 0.25 }
    }
  };
}

function setupFadeIn() {
  const observer = new IntersectionObserver(entries => {
    entries.forEach(entry => { if (entry.isIntersecting) entry.target.classList.add("is-visible"); });
  }, { threshold: 0.12 });
  document.querySelectorAll(".section-fade").forEach(el => observer.observe(el));
}

function ensureTooltip() {
  let tooltip = document.querySelector(".tooltip");
  if (!tooltip) {
    tooltip = document.createElement("div");
    tooltip.className = "tooltip";
    document.body.appendChild(tooltip);
  }
  return tooltip;
}

function chartColor(label) {
  return ARTICLE_COLORS[label] || WORD_PALETTE[Math.abs(hashString(label)) % WORD_PALETTE.length];
}

function cssId(text) { return String(text).replace(/\s+/g, "-").replace(/[^가-힣ㄱ-ㅎㅏ-ㅣa-zA-Z0-9_-]/g, ""); }
function hashString(text) {
  return Array.from(String(text)).reduce((acc, ch) => acc + ch.charCodeAt(0), 0);
}
function debounce(fn, wait) {
  let t;
  return (...args) => { clearTimeout(t); t = setTimeout(() => fn(...args), wait); };
}
